class Solution:
    def minStartingIndex(self, s: str, pattern: str) -> int:
        m, n = len(pattern), len(s)
        diff_count = 0
        left = 0
        for right in range(n):
            if s[right] != pattern[right % m]:
                diff_count += 1
            if right >= m:
                if s[right - m] != pattern[(right - m) % m]:
                    diff_count -= 1
            if diff_count > 1:
                continue
            if diff_count == 0 or (right >= m - 1 and diff_count == 1):
                return right - m + 1
        return -1
```
